INSERT INTO "placement_tests" ("id", "title", "description", "total_questions", "duration_minutes", "is_active", "created_at", "updated_at") VALUES (1, 'Kiểm tra xếp lớp JLPT', 'Bài test giúp đánh giá trình độ N5/N4/N3 của bạn.', 20, 25, true, '2026-03-16T07:55:09.6617235', '2026-03-16T07:55:09.6617235');
INSERT INTO "placement_questions" ("id", "level_label", "sort_order", "text") VALUES (1, 'N5', 1, 'これは＿＿ペンです。');
INSERT INTO "placement_questions" ("id", "level_label", "sort_order", "text") VALUES (2, 'N5', 2, 'いま、＿＿ですか。');
INSERT INTO "placement_questions" ("id", "level_label", "sort_order", "text") VALUES (3, 'N5', 3, 'わたしは毎日７時に＿＿。');
INSERT INTO "placement_questions" ("id", "level_label", "sort_order", "text") VALUES (4, 'N5', 4, '教室に学生が３０＿＿います。');
INSERT INTO "placement_questions" ("id", "level_label", "sort_order", "text") VALUES (5, 'N5', 5, '明日＿＿に行きます。');
INSERT INTO "placement_questions" ("id", "level_label", "sort_order", "text") VALUES (6, 'N5', 6, 'これはいくらですか。＿＿、１０００円です。');
INSERT INTO "placement_questions" ("id", "level_label", "sort_order", "text") VALUES (7, 'N5', 7, 'わたしのしゅみは本を＿＿ことです。');
INSERT INTO "placement_questions" ("id", "level_label", "sort_order", "text") VALUES (8, 'N5', 8, '山田さんは日本語がとても＿＿です。');
INSERT INTO "placement_questions" ("id", "level_label", "sort_order", "text") VALUES (9, 'N5', 9, '日曜日、どこ＿＿行きましたか。');
INSERT INTO "placement_questions" ("id", "level_label", "sort_order", "text") VALUES (10, 'N5', 10, 'きのうは＿＿でしたか。');
INSERT INTO "placement_questions" ("id", "level_label", "sort_order", "text") VALUES (11, 'N5', 11, '＿＿、もう一度言ってください。');
INSERT INTO "placement_questions" ("id", "level_label", "sort_order", "text") VALUES (12, 'N5', 12, 'わたしは日本のアニメ＿＿好きです。');
INSERT INTO "placement_questions" ("id", "level_label", "sort_order", "text") VALUES (13, 'N5', 13, 'きょうは仕事が＿＿、とてもつかれました。');
INSERT INTO "placement_questions" ("id", "level_label", "sort_order", "text") VALUES (14, 'N5', 14, '田中さんはどこに＿＿か。');
INSERT INTO "placement_questions" ("id", "level_label", "sort_order", "text") VALUES (15, 'N5', 15, '電車で＿＿ください。');
INSERT INTO "placement_questions" ("id", "level_label", "sort_order", "text") VALUES (16, 'N4', 16, '田中さんは今、日本で＿＿います。');
INSERT INTO "placement_questions" ("id", "level_label", "sort_order", "text") VALUES (17, 'N4', 17, '雨が＿＿、サッカーの試合は中止になりました。');
INSERT INTO "placement_questions" ("id", "level_label", "sort_order", "text") VALUES (18, 'N4', 18, 'きのうは本を読んだり、音楽を聞いたり＿＿。');
INSERT INTO "placement_questions" ("id", "level_label", "sort_order", "text") VALUES (19, 'N4', 19, 'まだ夕ごはんを＿＿。');
INSERT INTO "placement_questions" ("id", "level_label", "sort_order", "text") VALUES (20, 'N4', 20, '明日、雨が降る＿＿しれません。');
INSERT INTO "placement_questions" ("id", "level_label", "sort_order", "text") VALUES (21, 'N4', 21, 'A: 先生、宿題を忘れてしまいました。\nB: そうですか。＿＿、こんどは気をつけてくださいね。');
INSERT INTO "placement_questions" ("id", "level_label", "sort_order", "text") VALUES (22, 'N4', 22, 'A: いっしょに映画を見に行きませんか。\nB: ＿＿、今日は用事があります。');
INSERT INTO "placement_questions" ("id", "level_label", "sort_order", "text") VALUES (23, 'N4', 23, 'あした雨が＿＿、ハイキングに行きます。');
INSERT INTO "placement_questions" ("id", "level_label", "sort_order", "text") VALUES (24, 'N4', 24, 'これは日本人＿＿もむずかしい本です。');
INSERT INTO "placement_questions" ("id", "level_label", "sort_order", "text") VALUES (25, 'N4', 25, '兄はギターを＿＿ことができます。');
INSERT INTO "placement_questions" ("id", "level_label", "sort_order", "text") VALUES (26, 'N4', 26, '【読解】「田中さんは毎朝６時に起きて、朝ごはんを食べてから会社に行きます。週末はよく家族と買い物をします。」\n田中さんは＿＿と買い物をしますか。');
INSERT INTO "placement_questions" ("id", "level_label", "sort_order", "text") VALUES (27, 'N4', 27, '【会話】A: 駅までどうやって行きますか。\nB: このバスに＿＿行けますよ。');
INSERT INTO "placement_questions" ("id", "level_label", "sort_order", "text") VALUES (28, 'N4', 28, '【文法】日本語を上手に話せる＿＿、毎日練習しています。');
INSERT INTO "placement_questions" ("id", "level_label", "sort_order", "text") VALUES (29, 'N4', 29, '【語彙】１か月に日本語の本を何＿＿読みますか。');
INSERT INTO "placement_questions" ("id", "level_label", "sort_order", "text") VALUES (30, 'N4', 30, '【読解】「来週、会社で大きいプロジェクトが始まります。わたしはリーダーになったので、とても忙しくなりそうです。」\n筆者は来週からどうなりそうですか。');
INSERT INTO "placement_questions" ("id", "level_label", "sort_order", "text") VALUES (31, 'N3', 31, '日本では、春になると桜が咲く＿＿です。');
INSERT INTO "placement_questions" ("id", "level_label", "sort_order", "text") VALUES (32, 'N3', 32, 'そんなに夜遅くまでゲームをしていたら、体に悪い＿＿。');
INSERT INTO "placement_questions" ("id", "level_label", "sort_order", "text") VALUES (33, 'N3', 33, '大事な書類をなくして＿＿いました。');
INSERT INTO "placement_questions" ("id", "level_label", "sort_order", "text") VALUES (34, 'N3', 34, '健康のために、毎朝３０分歩くことに＿＿。');
INSERT INTO "placement_questions" ("id", "level_label", "sort_order", "text") VALUES (35, 'N3', 35, '彼は日本に来た＿＿、日本語が上手になった。');
INSERT INTO "placement_questions" ("id", "level_label", "sort_order", "text") VALUES (36, 'N3', 36, '【読解】「私は１０年前に日本へ留学しました。最初はほとんど日本語が話せませんでしたが、毎日ニュースを見たり、日本人の友達と話したりして、少しずつ上手になりました。」\n筆者はどうやって日本語が上手になりましたか。');
INSERT INTO "placement_questions" ("id", "level_label", "sort_order", "text") VALUES (37, 'N3', 37, '【会話】A: あの、新しいプロジェクトの資料、もう読みましたか。\nB: いいえ、＿＿。今日の午後読むつもりです。');
INSERT INTO "placement_questions" ("id", "level_label", "sort_order", "text") VALUES (38, 'N3', 38, '【文法】日本語だけでなく、英語＿＿勉強する必要があります。');
INSERT INTO "placement_questions" ("id", "level_label", "sort_order", "text") VALUES (39, 'N3', 39, '【読解】「この会社では、１日に３回ミーティングがあります。１回目は９時、２回目は１３時、３回目は１７時に行われます。」\nミーティングは１日に何回行われますか。');
INSERT INTO "placement_questions" ("id", "level_label", "sort_order", "text") VALUES (40, 'N3', 40, '【読解】「最近、日本語の勉強があまり進んでいません。仕事が忙しくて、家に帰るといつも疲れてしまいます。それでも、日本語が上手になりたいので、毎日３０分だけでも勉強を続けようと思っています。」\n筆者はこれからどうしようと思っていますか。');
